    fn emit_seq_count_by(
        &self,
        func: &mut Function,
        seq: ValueId,
        predicate: ValueId,
    ) -> Result<(), CodegenError> {
        self.emit_get(func, seq);
        func.instruction(&Instruction::LocalSet(self.scratch_i32));

        if let Some(elem_ty) = self.linear_collection_element_ty(seq) {
            self.emit_seq_count_by_list_from_local(func, self.scratch_i32, elem_ty, predicate)?;
            return Ok(());
        }

        match self.core_seq_element_ty(seq) {
            Some(Ty::Int) => {
                let int_elem_ty = Ty::Int;
                func.instruction(&Instruction::LocalGet(self.scratch_i32));
                func.instruction(&Instruction::I32Load(MemArg {
                    offset: 0,
                    align: 2,
                    memory_index: 0,
                }));
                func.instruction(&Instruction::LocalSet(self.scratch_i32_2));
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(SEQ_KIND_MATERIALIZED_LIST));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Result(ValType::I64)));
                self.emit_seq_load_materialized_list_source_from_local(
                    func,
                    self.scratch_i32,
                    self.scratch_i32_10,
                );
                self.emit_seq_count_by_list_from_local(
                    func,
                    self.scratch_i32_10,
                    &int_elem_ty,
                    predicate,
                )?;
                func.instruction(&Instruction::Else);
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(SEQ_KIND_RANGE));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Result(ValType::I64)));
                self.emit_seq_count_by_range_from_local(func, self.scratch_i32, predicate)?;
                func.instruction(&Instruction::Else);
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(SEQ_KIND_BITSET_VALUES));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Result(ValType::I64)));
                self.emit_seq_to_list_bitset_values_from_local(
                    func,
                    self.scratch_i32,
                    self.scratch_i32_10,
                );
                self.emit_seq_count_by_list_from_local(
                    func,
                    self.scratch_i32_10,
                    &int_elem_ty,
                    predicate,
                )?;
                func.instruction(&Instruction::Else);
                func.instruction(&Instruction::Unreachable);
                func.instruction(&Instruction::I64Const(0));
                func.instruction(&Instruction::End);
                func.instruction(&Instruction::End);
                func.instruction(&Instruction::End);
            }
            Some(Ty::Char) => {
                func.instruction(&Instruction::LocalGet(self.scratch_i32));
                func.instruction(&Instruction::I32Load(MemArg {
                    offset: 0,
                    align: 2,
                    memory_index: 0,
                }));
                func.instruction(&Instruction::LocalSet(self.scratch_i32_2));
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(SEQ_KIND_MATERIALIZED_LIST));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Result(ValType::I64)));
                self.emit_seq_load_materialized_list_source_from_local(
                    func,
                    self.scratch_i32,
                    self.scratch_i32_10,
                );
                self.emit_seq_count_by_list_from_local(
                    func,
                    self.scratch_i32_10,
                    &Ty::Char,
                    predicate,
                )?;
                func.instruction(&Instruction::Else);
                self.emit_seq_count_by_chars_from_local(func, self.scratch_i32, predicate)?;
                func.instruction(&Instruction::End);
            }
            Some(Ty::String) => {
                func.instruction(&Instruction::LocalGet(self.scratch_i32));
                func.instruction(&Instruction::I32Load(MemArg {
                    offset: 0,
                    align: 2,
                    memory_index: 0,
                }));
                func.instruction(&Instruction::LocalSet(self.scratch_i32_2));

                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(SEQ_KIND_MATERIALIZED_LIST));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Result(ValType::I64)));
                self.emit_seq_load_materialized_list_source_from_local(
                    func,
                    self.scratch_i32,
                    self.scratch_i32_10,
                );
                self.emit_seq_count_by_list_from_local(
                    func,
                    self.scratch_i32_10,
                    &Ty::String,
                    predicate,
                )?;
                func.instruction(&Instruction::Else);
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(2));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Result(ValType::I64)));
                self.emit_seq_count_by_lines_from_local(func, self.scratch_i32, predicate)?;
                func.instruction(&Instruction::Else);
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(3));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Result(ValType::I64)));
                self.emit_seq_count_by_split_from_local(func, self.scratch_i32, predicate)?;
                func.instruction(&Instruction::Else);
                func.instruction(&Instruction::Unreachable);
                func.instruction(&Instruction::I64Const(0));
                func.instruction(&Instruction::End);
                func.instruction(&Instruction::End);
                func.instruction(&Instruction::End);
            }
            Some(elem_ty) => {
                self.emit_seq_materialize_core_to_list_from_local(
                    func,
                    self.scratch_i32,
                    elem_ty,
                    self.scratch_i32_10,
                )?;
                self.emit_seq_count_by_list_from_local(
                    func,
                    self.scratch_i32_10,
                    elem_ty,
                    predicate,
                )?;
            }
            None => {
                return Err(CodegenError::UnsupportedInstruction(format!(
                    "seq_count_by over non-Seq receiver in Wasm: {:?}",
                    self.value_ty(seq)
                )));
            }
        }

        Ok(())
    }

