    fn emit_seq_fold(
        &self,
        func: &mut Function,
        seq: ValueId,
        init: ValueId,
        folder: ValueId,
        result_ty: &Ty,
    ) -> Result<(), CodegenError> {
        let acc_local = match result_ty {
            Ty::Float => self.seq_fold_acc_f64,
            Ty::Int => self.seq_fold_acc_i64,
            _ => self.seq_fold_acc_i32,
        };
        self.emit_get(func, init);
        func.instruction(&Instruction::LocalSet(acc_local));

        self.emit_get(func, seq);
        func.instruction(&Instruction::LocalSet(self.scratch_i32));

        let can_fast_path_char_string_fold = result_ty == &Ty::String
            && self.value_is_empty_string_const(init)
            && self.is_string_concat_char_to_string_folder(folder);

        if can_fast_path_char_string_fold
            && let Some(elem_ty) = self.linear_collection_element_ty(seq)
            && *elem_ty == Ty::Char
        {
            self.emit_string_from_char_list_local(func, self.scratch_i32, acc_local);
            func.instruction(&Instruction::LocalGet(acc_local));
            return Ok(());
        }

        if let Some(elem_ty) = self.linear_collection_element_ty(seq) {
            self.emit_seq_fold_list_from_local(func, self.scratch_i32, elem_ty, acc_local, folder)?;
            func.instruction(&Instruction::LocalGet(acc_local));
            return Ok(());
        }

        match self.core_seq_element_ty(seq) {
            Some(Ty::Int) => {
                let int_elem_ty = Ty::Int;
                func.instruction(&Instruction::LocalGet(self.scratch_i32));
                func.instruction(&Instruction::I32Load(MemArg {
                    offset: 0,
                    align: 2,
                    memory_index: 0,
                }));
                func.instruction(&Instruction::LocalSet(self.scratch_i32_2));
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(SEQ_KIND_MATERIALIZED_LIST));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Empty));
                self.emit_seq_load_materialized_list_source_from_local(
                    func,
                    self.scratch_i32,
                    self.scratch_i32_10,
                );
                self.emit_seq_fold_list_from_local(
                    func,
                    self.scratch_i32_10,
                    &int_elem_ty,
                    acc_local,
                    folder,
                )?;
                func.instruction(&Instruction::Else);
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(SEQ_KIND_RANGE));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Empty));
                self.emit_seq_fold_range_from_local(func, self.scratch_i32, acc_local, folder)?;
                func.instruction(&Instruction::Else);
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(SEQ_KIND_BITSET_VALUES));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Empty));
                let preserved_acc_local = match result_ty {
                    Ty::Int => self.scratch_i64_4,
                    Ty::Float => acc_local,
                    _ => self.scratch_i32,
                };
                if preserved_acc_local != acc_local {
                    func.instruction(&Instruction::LocalGet(acc_local));
                    func.instruction(&Instruction::LocalSet(preserved_acc_local));
                }
                self.emit_seq_to_list_bitset_values_from_local(
                    func,
                    self.scratch_i32,
                    self.scratch_i32_10,
                );
                if preserved_acc_local != acc_local {
                    func.instruction(&Instruction::LocalGet(preserved_acc_local));
                    func.instruction(&Instruction::LocalSet(acc_local));
                }
                self.emit_seq_fold_list_from_local(
                    func,
                    self.scratch_i32_10,
                    &int_elem_ty,
                    acc_local,
                    folder,
                )?;
                func.instruction(&Instruction::Else);
                func.instruction(&Instruction::Unreachable);
                func.instruction(&Instruction::End);
                func.instruction(&Instruction::End);
                func.instruction(&Instruction::End);
            }
            Some(Ty::Char) => {
                func.instruction(&Instruction::LocalGet(self.scratch_i32));
                func.instruction(&Instruction::I32Load(MemArg {
                    offset: 0,
                    align: 2,
                    memory_index: 0,
                }));
                func.instruction(&Instruction::LocalSet(self.scratch_i32_2));
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(SEQ_KIND_MATERIALIZED_LIST));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Empty));
                self.emit_seq_load_materialized_list_source_from_local(
                    func,
                    self.scratch_i32,
                    self.scratch_i32_10,
                );
                if can_fast_path_char_string_fold {
                    self.emit_string_from_char_list_local(func, self.scratch_i32_10, acc_local);
                } else {
                    self.emit_seq_fold_list_from_local(
                        func,
                        self.scratch_i32_10,
                        &Ty::Char,
                        acc_local,
                        folder,
                    )?;
                }
                func.instruction(&Instruction::Else);
                if can_fast_path_char_string_fold {
                    func.instruction(&Instruction::LocalGet(self.scratch_i32));
                    func.instruction(&Instruction::I32Load(MemArg {
                        offset: 8,
                        align: 2,
                        memory_index: 0,
                    }));
                    func.instruction(&Instruction::LocalSet(acc_local));
                } else {
                    self.emit_seq_fold_chars_from_local(func, self.scratch_i32, acc_local, folder)?;
                }
                func.instruction(&Instruction::End);
            }
            Some(Ty::String) => {
                func.instruction(&Instruction::LocalGet(self.scratch_i32));
                func.instruction(&Instruction::I32Load(MemArg {
                    offset: 0,
                    align: 2,
                    memory_index: 0,
                }));
                func.instruction(&Instruction::LocalSet(self.scratch_i32_2));
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(SEQ_KIND_MATERIALIZED_LIST));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Empty));
                self.emit_seq_load_materialized_list_source_from_local(
                    func,
                    self.scratch_i32,
                    self.scratch_i32_10,
                );
                self.emit_seq_fold_list_from_local(
                    func,
                    self.scratch_i32_10,
                    &Ty::String,
                    acc_local,
                    folder,
                )?;
                func.instruction(&Instruction::Else);
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(2));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Empty));
                self.emit_seq_fold_lines_from_local(func, self.scratch_i32, acc_local, folder)?;
                func.instruction(&Instruction::Else);
                func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
                func.instruction(&Instruction::I32Const(3));
                func.instruction(&Instruction::I32Eq);
                func.instruction(&Instruction::If(BlockType::Empty));
                self.emit_seq_fold_split_from_local(func, self.scratch_i32, acc_local, folder)?;
                func.instruction(&Instruction::Else);
                func.instruction(&Instruction::Unreachable);
                func.instruction(&Instruction::End);
                func.instruction(&Instruction::End);
                func.instruction(&Instruction::End);
            }
            Some(elem_ty) => {
                self.emit_seq_materialize_core_to_list_from_local(
                    func,
                    self.scratch_i32,
                    elem_ty,
                    self.scratch_i32_10,
                )?;
                self.emit_seq_fold_list_from_local(
                    func,
                    self.scratch_i32_10,
                    elem_ty,
                    acc_local,
                    folder,
                )?;
            }
            None => {
                return Err(CodegenError::UnsupportedInstruction(format!(
                    "seq_fold over non-Seq receiver in Wasm: {:?}",
                    self.value_ty(seq)
                )));
            }
        }

        func.instruction(&Instruction::LocalGet(acc_local));
        Ok(())
    }

    fn emit_seq_fold_list_from_local(
        &self,
        func: &mut Function,
        list_local: u32,
        elem_ty: &Ty,
        acc_local: u32,
        folder: ValueId,
    ) -> Result<(), CodegenError> {
        let elem_local = self.temp_local_for_ty(elem_ty);
        self.emit_load_list_len_and_data_from_local(
            func,
            list_local,
            self.scratch_i32_3,
            self.scratch_i32_4,
        );

        func.instruction(&Instruction::I32Const(0));
        func.instruction(&Instruction::LocalSet(self.scratch_i32_5));

        func.instruction(&Instruction::Block(BlockType::Empty));
        func.instruction(&Instruction::Loop(BlockType::Empty));
        func.instruction(&Instruction::LocalGet(self.scratch_i32_5));
        func.instruction(&Instruction::LocalGet(self.scratch_i32_3));
        func.instruction(&Instruction::I32GeU);
        func.instruction(&Instruction::BrIf(1));

        func.instruction(&Instruction::LocalGet(self.scratch_i32_4));
        func.instruction(&Instruction::LocalGet(self.scratch_i32_5));
        func.instruction(&Instruction::I32Const(8));
        func.instruction(&Instruction::I32Mul);
        func.instruction(&Instruction::I32Add);
        self.emit_typed_load(func, elem_ty, 0);
        func.instruction(&Instruction::LocalSet(elem_local));

        func.instruction(&Instruction::LocalGet(acc_local));
        func.instruction(&Instruction::LocalGet(elem_local));
        self.emit_indirect_call_two_args(func, folder)?;
        func.instruction(&Instruction::LocalSet(acc_local));

        func.instruction(&Instruction::LocalGet(self.scratch_i32_5));
        func.instruction(&Instruction::I32Const(1));
        func.instruction(&Instruction::I32Add);
        func.instruction(&Instruction::LocalSet(self.scratch_i32_5));
        func.instruction(&Instruction::Br(0));
        func.instruction(&Instruction::End);
        func.instruction(&Instruction::End);
        Ok(())
    }

