    fn emit_seq_compute_loaded_range_len_to_local(&self, func: &mut Function, len_local: u32) {
        func.instruction(&Instruction::LocalGet(self.scratch_i64_2));
        func.instruction(&Instruction::LocalGet(self.scratch_i64));
        func.instruction(&Instruction::I64LeS);
        func.instruction(&Instruction::If(BlockType::Empty));
        func.instruction(&Instruction::I32Const(0));
        func.instruction(&Instruction::LocalSet(len_local));
        func.instruction(&Instruction::Else);
        func.instruction(&Instruction::LocalGet(self.scratch_i64_2));
        func.instruction(&Instruction::LocalGet(self.scratch_i64));
        func.instruction(&Instruction::I64Sub);
        func.instruction(&Instruction::I32WrapI64);
        func.instruction(&Instruction::LocalSet(len_local));
        func.instruction(&Instruction::End);
    }

    fn range_list_builder_i32_locals(&self, out_list_local: u32) -> [u32; 4] {
        let candidates = [
            self.scratch_i32_9,
            self.scratch_i32_10,
            self.scratch_i32_11,
            self.scratch_i32_12,
            self.scratch_i32_16,
        ];
        let mut picked = [0; 4];
        let mut next = 0;
        for candidate in candidates {
            if candidate != out_list_local {
                picked[next] = candidate;
                next += 1;
                if next == picked.len() {
                    return picked;
                }
            }
        }
        panic!("missing i32 scratch locals for range list builder");
    }

    fn range_list_builder_output_i32_local(&self, out_list_local: u32) -> u32 {
        self.pick_i32_scratch_local_excluding(&[out_list_local])
    }

    fn pick_i32_scratch_local_excluding(&self, excluded: &[u32]) -> u32 {
        let candidates = [
            self.scratch_i32_7,
            self.scratch_i32_8,
            self.scratch_i32_16,
            self.scratch_i32_12,
            self.scratch_i32_11,
            self.scratch_i32_10,
            self.scratch_i32_9,
        ];
        for candidate in candidates {
            if !excluded.contains(&candidate) {
                return candidate;
            }
        }
        panic!("missing distinct i32 scratch local");
    }

    fn emit_option_unwrap_or(
        &self,
        func: &mut Function,
        option: ValueId,
        fallback: ValueId,
        result_ty: &Ty,
    ) -> Result<(), CodegenError> {
        let input_option_ty = self.value_ty(option);
        let (some_ty, some_tag, none_tag) =
            self.lookup_option_variant_tags(input_option_ty, "option_unwrap_or")?;
        let temp_local = self.temp_local_for_ty(result_ty);

        self.emit_get(func, option);
        func.instruction(&Instruction::LocalSet(self.scratch_i32));

        func.instruction(&Instruction::LocalGet(self.scratch_i32));
        func.instruction(&Instruction::I32Load(MemArg {
            offset: 0,
            align: 2,
            memory_index: 0,
        }));
        func.instruction(&Instruction::LocalSet(self.scratch_i32_2));

        func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
        func.instruction(&Instruction::I32Const(some_tag as i32));
        func.instruction(&Instruction::I32Eq);
        func.instruction(&Instruction::If(BlockType::Empty));
        self.emit_option_payload_load_from_local(func, self.scratch_i32, some_ty);
        func.instruction(&Instruction::LocalSet(temp_local));
        func.instruction(&Instruction::Else);
        func.instruction(&Instruction::LocalGet(self.scratch_i32_2));
        func.instruction(&Instruction::I32Const(none_tag as i32));
        func.instruction(&Instruction::I32Eq);
        func.instruction(&Instruction::I32Eqz);
        self.emit_trap_if_true(func);
        self.emit_get(func, fallback);
        func.instruction(&Instruction::LocalSet(temp_local));
        func.instruction(&Instruction::End);

        func.instruction(&Instruction::LocalGet(temp_local));
        Ok(())
    }

